import { useState } from "react";
import "./UserNavbar.css";

export default function UserNavbar() {
  const [menuOpen, setMenuOpen] = useState(false);

  const toggleMenu = () => {
    setMenuOpen(!menuOpen);
  };

  const handleNavClick = () => {
    setMenuOpen(false); // Close the menu when a link is clicked
  };

  return (
    <nav className="user-navbar">
      <h2 className="user-logo">User Panel</h2>

      {/* Hamburger Menu for Mobile */}
      <button className="menu-toggle" onClick={toggleMenu}>
        ☰
      </button>

      {/* Navigation Links */}
      <ul className={`user-nav-links ${menuOpen ? "open" : ""}`}>
        <li onClick={handleNavClick}>Dashboard</li>
        <li onClick={handleNavClick}>Library Explorer</li>
        <li onClick={handleNavClick}>Borrow & Return</li>
        <li>
          <button className="logout-btn" onClick={handleNavClick}>Logout</button>
        </li>
      </ul>
    </nav>
  );
}
